import java.util.*;class P2{public static void main(String[] a){Scanner s=new Scanner(System.in);int[] age=new int[3];double[] h=new double[3];String[] n={"Amar","Akbar","Anthony"};for(int i=0;i<3;i++){age[i]=s.nextInt();h[i]=s.nextDouble();}int y=0;double t=h[0];for(int i=1;i<3;i++){if(age[i]<age[y])y=i;if(h[i]>t){t=h[i];}}System.out.println(n[y]);for(int i=0;i<3;i++)if(h[i]==t)System.out.println(n[i]);}}